/* ============================================================
   STEP 1: Generate VALUES text for Posts
   Run this, copy the single-cell result into Step 4's paste area
   ============================================================ */

SELECT
    CASE WHEN ROW_NUMBER() OVER (ORDER BY PostId) = 1 THEN '    (' ELSE '    ,(' END
    + CAST(PostId AS VARCHAR(10)) + ', '
    + N'''' + REPLACE(REPLACE(REPLACE(Title, '''', ''''''), CHAR(13)+CHAR(10), CHAR(10)), CHAR(10), '''+CHAR(13)+CHAR(10)+''') + ''', '
    + N'''' + REPLACE(REPLACE(REPLACE(PreviewText, '''', ''''''), CHAR(13)+CHAR(10), CHAR(10)), CHAR(10), '''+CHAR(13)+CHAR(10)+''') + ''', '
    + N'''' + REPLACE(REPLACE(REPLACE(CAST(Body AS NVARCHAR(MAX)), '''', ''''''), CHAR(13)+CHAR(10), CHAR(10)), CHAR(10), '''+CHAR(13)+CHAR(10)+''') + ''', '
    + ISNULL('''' + CONVERT(VARCHAR(19), ReleaseDate, 120) + '''', 'NULL') + ', '
    + ISNULL('''' + CONVERT(VARCHAR(19), ExpireDate, 120) + '''', 'NULL') + ', '
    + CAST(CommentsEnabled AS VARCHAR(1)) + ', '
    + CAST(Approved AS VARCHAR(1)) + ', '
    + CAST(ViewCount AS VARCHAR(20)) + ', '
    + '''' + CONVERT(VARCHAR(19), CreatedDate, 120) + ''', '
    + '''' + CAST(CreatedByFk AS VARCHAR(36)) + ''', '
    + '''' + CONVERT(VARCHAR(19), ModifiedDate, 120) + ''', '
    + '''' + CAST(ModifiedByFk AS VARCHAR(36)) + ''', '
    + ISNULL('''' + REPLACE(REPLACE(REPLACE(ImageUrl, '''', ''''''), CHAR(13)+CHAR(10), CHAR(10)), CHAR(10), '''+CHAR(13)+CHAR(10)+''') + '''', 'NULL') + ', '
    + CASE WHEN Archived IS NULL THEN 'NULL' ELSE CAST(Archived AS VARCHAR(1)) END + ', '
    + CASE WHEN CircleOfTrust IS NULL THEN 'NULL' ELSE CAST(CircleOfTrust AS VARCHAR(1)) END
    + ')' AS RowSql
FROM Posts
ORDER BY PostId;

/* ============================================================
   STEP 2: Generate VALUES lines for PostCategories (one row = one line)
   select * from postcategories where categoryfk not in (select categoryid from categories)
   select * from categories
   ============================================================ */
SELECT
    CASE WHEN ROW_NUMBER() OVER (ORDER BY PostCategoryId) = 1 THEN '    (' ELSE '    ,(' END
    + CAST(PostCategoryId AS VARCHAR(10)) + ', '
    + CAST(PostFk AS VARCHAR(10)) + ', '
    + CAST(CategoryFk AS VARCHAR(10))
    + ')' AS RowSql
FROM PostCategories
ORDER BY PostCategoryId;


RETURN;  --Manually run from here down


/* ============================================================
   STEP 3: Create the temp tables (target side)
   ============================================================ */
CREATE TABLE #TempPosts (
    PostId          INT              NOT NULL,
    Title           NVARCHAR (MAX)   NOT NULL,
    PreviewText     NVARCHAR (MAX)   NOT NULL,
    Body            NVARCHAR (MAX)   NOT NULL,
    ReleaseDate     SMALLDATETIME    NULL,
    ExpireDate      SMALLDATETIME    NULL,
    CommentsEnabled BIT              NOT NULL,
    Approved        BIT              NOT NULL,
    ViewCount       BIGINT           NOT NULL,
    CreatedDate     SMALLDATETIME    NOT NULL,
    CreatedByFk     UNIQUEIDENTIFIER NOT NULL,
    ModifiedDate    SMALLDATETIME    NOT NULL,
    ModifiedByFk    UNIQUEIDENTIFIER NOT NULL,
    ImageUrl        NVARCHAR (MAX)   NULL,
    Archived        BIT              NULL,
    CircleOfTrust   BIT              NULL
);

CREATE TABLE #TempPostCategories (
    PostCategoryId INT NOT NULL,
    PostFk         INT NOT NULL,
    CategoryFk     INT NOT NULL
);

/* ============================================================
   STEP 4: Populate #TempPosts
   ============================================================ */
INSERT INTO #TempPosts
    (PostId, Title, PreviewText, Body, ReleaseDate, ExpireDate,
     CommentsEnabled, Approved, ViewCount, CreatedDate, CreatedByFk,
     ModifiedDate, ModifiedByFk, ImageUrl, Archived, CircleOfTrust)
VALUES
--BEGIN paste Step 1 output here

        (1, 'Welcome to our site', 'Hi and welcome to our website!  We created this website so you can see what we''ve been up to lately and to share some photos.  The plan is to update this with what is happening here in Colorado.  So stop on by from time to time!', 'Hi and welcome to our website!  We created this website so you can see what we''ve been up to lately and to share some photos.  The plan is to update this with what is happening here in Colorado.  So stop on by from time to time!', '2006-07-05 00:00:00', NULL, 1, 1, 3932, '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(2, 'Photo Albums', 'The bulk of the content on this site is available through the [Photo Album](www.johnandjeri.com/albums/default.aspx).  We managed to post our wedding photos, honeymoon in Jamaica, our new house and a bunch of other related photos. Let us know what you think by sending us an [email](www.johnandjeri.com/contactus.aspx).', 'The bulk of the content on this site is available through the [Photo Album](www.johnandjeri.com/albums/default.aspx).  We managed to post our wedding photos, honeymoon in Jamaica, our new house and a bunch of other related photos. Let us know what you think by sending us an [email](www.johnandjeri.com/contactus.aspx).', '2006-07-05 00:00:00', NULL, 1, 1, 2413, '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(3, 'Annual 4th of July Hike', 'We took a trip up to the mountains over the July 4th holiday.  We backpacked in about 4 miles over some pretty grueling landscape and were rewarded with some incredible fishing!', 'We took a trip up to the mountains over the July 4th holiday.  We backpacked in about 4 miles over some pretty grueling landscape and were rewarded with some incredible fishing!  We caught some beautiful native cut-throat trout and some awesome brook trout.  Check out our catch in the [Photo Album](http://localhost/Hazeltine/Albums/folderview.aspx?path=Hunting+and+Fishing%2fFishing+Trips+2006%2f).', '2006-07-05 00:00:00', NULL, 1, 1, 2162, '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(4, 'The great house swap of 2006', 'We finally pulled the trigger on upgrading our house situation.', 'Our house went on the Market back in April of 2006.  With much relief, we sold it and closed on the deal in July of 2007.  The new owner is allowing us to rent the house through the middle of August, which is when we hope to close on our new home.  The new house is just a couple of miles from where we live now.  We have been dropping by on a regular basis and taking a photo journal of the progress.  To see all of our pictures, go to our [Photo Album](http://www.johnandjeri.com/Albums/folderview.aspx?path=New+House%2f).', '2006-07-05 00:00:00', NULL, 1, 1, 2359, '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2006-07-05 00:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(5, 'Trip to Australia', 'We are off to chase Kangaroos & Koalas.  There is still some last minute packing, but we found some time to create a small post.', ''+CHAR(13)+CHAR(10)+'Well, here we go. We are finally taking that vacation we have been talking about forever. The funny part is that it is snowing in Denver while we are taking care of our last minute items. '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We decided to use our web site to help us remember what sort of things we get to see & do. We hope to update the site with a new article each week or so. A lot of it will depend on access to the internet''on someone else''s computer. We just created the functionality to create these posts, so there are no promises that it is not just a little bit buggy. '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'For those not quite aware of what our trip looks like, here is the brief summary. We are heading from Denver to Sydney. From Sydney, Australia to Christchruch, New Zealand. We will spend a little time in the south island and then fly to the north island. From there we head back to Cairns, Australia near the Great Barrier Reef. We will then head down the east coast of Australia and finish our trip back in Sydney. '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We will finally get to verify if the water really swirls down the drain backwards, among other things. Be sure to add your comments to our postings and we will see you on the flip side.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'G''day mate!'+CHAR(13)+CHAR(10)+'', '2007-03-24 00:00:00', NULL, 1, 1, 2337, '2007-03-24 15:35:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-03-24 15:35:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(6, 'Day 1: Visas & Koalas', 'We are on the other side of the world...and it only took 18 hours and some heart wrenching drama along the way.', ''+CHAR(13)+CHAR(10)+'So, there we were, standing at the mercy of the United Airlines ticketing agent''I will add, we looked perfectly harmless and fairly happy (with minimal sleep).  Then we heard the line''&rdquo;Can I see your Visas?&rdquo;.  Now imagine, waiting years to make this trip, taking a years worth of vacation time, scheduling connecting flights, glacier trips, kayak trips, ''.  And the only thing we could muster up was a simple, fleeting ''no ma am&rdquo;. Now you see, we pride ourselves in with our ''attention to detail&rdquo;.  That was sort of a big oversight.  You would think something as big as a visa required to enter your vacation would have popped up on the radar somewhere.  Well, it didn''t!!!  Good news though, it turns out that Australia is the only country in the world that allows an electronic visa application.  The very nice and kind lady, Aimee Nutini, quickly brought our blood pressure back to normal and hooked us up.  We checked into our hotel in Sydney at 9:00 AM Monday morning.  That being said, we are having a great trip.  It is still day one with no (non air) sleep yet.  It has been less than 12 hours and we touched a python (Jeri too!), a two-headed skink, a starfish, and a sea cucumber.  We also got our first glimpse of a crocodile, wallaby, penguins, sharks, and koalas.  We finished the afternoon off with a drink in Darling Harbour (note the misspelling'') and we are contemplating what to do for dinner.  This pretty much ends our first post in our private version of the amazing race''.  Make sure to shoot us some comments to this''feel free to offer up some suggestions on what to do next!'+CHAR(13)+CHAR(10)+'', '2006-03-26 00:00:00', NULL, 1, 1, 2528, '2007-03-26 02:01:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-03-26 02:07:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(7, 'Day 3: Exiting Land of Oz', 'If you are still wondering, we did get in the country...now we are on our way out.  it is really tomorrow here.', 'Dateline 28 March 2007 9:00AM'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'After a couple days visiting the Koalas, Wallabies, and very big Bats, we are heading on to stop 2, Queenstown via Christchurch.  So far we have recorded two sun burns and a fairly tiring trek to all the touristy spots we could find.  Now we are getting set to try some adventure, kiwi style.  Gotta run, they are starting to board our plane.', '2007-03-26 00:00:00', NULL, 1, 1, 2380, '2007-03-27 19:13:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-03-27 19:16:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(8, 'Day 1 - PartII: Visas & Koalas', 'The ticket agent at United Saved the day.', ''+CHAR(13)+CHAR(10)+'Now you see, we pride ourselves in with our ''attention to detail&rdquo;.  That was sort of a big oversight.  You would think something as big as a visa required to enter your vacation would have popped up on the radar somewhere.  Well, it didn''t!!!  Good news though, it turns out that Australia is the only country in the world that allows an electronic visa application.  The very nice and kind lady, Aimee Nutini, quickly brought our blood pressure back to normal and hooked us up.'+CHAR(13)+CHAR(10)+'', '2007-03-26 00:00:00', NULL, 1, 1, 2260, '2007-03-28 18:08:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-03-28 18:08:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(9, 'Day 1 - PartIII: Visas & Koalas', 'Finally, made it to Sydney.', ''+CHAR(13)+CHAR(10)+'We checked into our hotel in Sydney at 9:00 AM Monday morning.  That being said, we are having a great trip.  It is still day one with no (non air) sleep yet.  It has been less than 12 hours and we touched a python (Jeri too!), a two-headed skink, a starfish, and a sea cucumber.  We also got our first glimpse of a crocodile, wallaby, penguins, sharks, and koalas.  We finished the afternoon off with a drink in Darling Harbour (note the misspelling'') and we are contemplating what to do for dinner.  This pretty much ends our first post in our private version of the amazing race''.  Make sure to shoot us some comments to this''feel free to offer up some suggestions on what to do next!'+CHAR(13)+CHAR(10)+'', '2007-03-26 00:00:00', NULL, 1, 1, 2340, '2007-03-28 18:09:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-03-28 18:09:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(10, 'New Features', 'By now you may have noticed a few new things on the site.  This is our last minute attempt to give us bit more functionality around posting real articles.', ''+CHAR(13)+CHAR(10)+'We decided to turn the site into a place we can post articles about our journies and such.  You may have noticed there are a few bugs (unexpected features) that went along with it.  It will continue to better, but since we are living off hostiles & internet cafes to make these postings, it may be a while before they are fixed.   If you see any bugs, feel free to list them in the comments below.'+CHAR(13)+CHAR(10)+'', '2007-03-27 00:00:00', NULL, 1, 1, 2393, '2007-03-28 18:14:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-11-09 18:57:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(11, 'Day 4 - Part I: Lost luggage over the Pacific', 'Welcome to New Zealand, the land of lost luggage, rugged mountains, and all sorts of Kiwi entertainment.', ''+CHAR(13)+CHAR(10)+'We were standing in front of the baggage carousal, fresh off our Air New Zealand flight from Sydney to Christchurch.  We had just a tic over an hour to find our bags, clear customs and check in for our next leg into Queenstown.  Normally this is a fairly easy task.  The airport is small, the customs folks are efficient, and we had plenty of time.  That is''until Jeri''s bag didn''t show up on the carousal.  We did our best to rush the lost bag process, but that was not quite good enough.  They handed us off to the scary customs officers behind the wall.  When we entered, there was nothing but long conveyor belts full of the contents of unwary travelers'' belongings.'+CHAR(13)+CHAR(10)+'', '2007-03-27 00:00:00', NULL, 1, 1, 2287, '2007-03-28 18:30:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-03-28 18:30:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(12, 'Day 4 - Part II: Lost luggage over the Pacific', 'Still adjusting to life with one back pack.  But the news is that the bag has been found and is on plane!', ''+CHAR(13)+CHAR(10)+'I am not sure what they were looking for, but my initial thought was that we only had 15 minutes until our connecting flight headed off to Queenstown without us.  We managed to find a sympathetic officer to help shuffle us through in time for us to reach Air New Zealand in time to hear the ticketing agent tell us the flight was locked.  Just as we were starting to rearrange our schedule, another ticket agent rushed us thought the ticket process and sent us running for the door.  We made it!  Albeit without Jeri''s back pack, but we made it.  Hopefully the survival kit they supplied will tide us over until the missing back pack finds its'' way back to us.'+CHAR(13)+CHAR(10)+'', '2007-03-27 00:00:00', NULL, 1, 1, 2216, '2007-03-28 18:32:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-03-28 18:33:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(13, 'Day 5: Luggage found & Screaming Mimmies', 'The adventure continues as our heroes learn that they can fly ([Canyon Swing](http://www.canyonswing.com)) & John discovers a really great dark beer!', ''+CHAR(13)+CHAR(10)+'Dateline: 30 March 2007, 11:18 AM -   All is right with the world - the luggage was returned yesterday morning, so to celebrate we flung ourselves off of a 109 meter (or is it metre?) platform and promptly lost our lunch.  Kidding - we didn''t lose our lunch.  It''s not really an experience that can be described so we bought the DVD of the adventure and can''t wait to show it!  Today we plan on skydiving, we''ll let you know how that goes!'+CHAR(13)+CHAR(10)+'', '2007-03-28 00:00:00', NULL, 1, 1, 2208, '2007-03-29 19:28:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-03-29 19:28:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(14, 'Day 5 Part II:  Luggage Found & Screaming Mimmies', 'Off to Te Anau', ''+CHAR(13)+CHAR(10)+'Okay - just kidding about the skydiving part.  At least for now...we''re off to Te Anua today so we can get ready to do some sea kayaking tomorrow.  Rumor has it that we might see some yellow-eyed penguins & fur seals!  More to follow....'+CHAR(13)+CHAR(10)+'', '2007-03-28 00:00:00', NULL, 1, 1, 2418, '2007-03-29 19:33:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-03-29 19:33:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(15, 'Day 7(?): Quest to find a penguin', 'We spent the past couple days in Te Anau getting our paddle on...and searching for the infamous yellow faced penguin.', ''+CHAR(13)+CHAR(10)+'Happy to report, we got our first non-walking and non-gravity related sport in yesterday.  We took a scenic bus\boat ride to our kayaks located in doubtful sound.  It is a good thing we planned a water sport, as it rained pretty much all day.  Doubtful is more of a rain forest than what we had expected.  There were waterfalls everywhere.  One of these days we will load some pictures to show you, but until then, just imagine a really big faucet.  After 18 k (?) of paddling, the penguin managed to elude us one more time.  We are back in Queenstown to relax a bit before heading up to the glacier. '+CHAR(13)+CHAR(10)+'', '2007-03-30 00:00:00', NULL, 1, 1, 2328, '2007-03-31 21:49:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-03-31 21:49:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(16, 'Houston!  We have pictures', 'After a bit of an arm wrestling session with internet cafe, we managed to get some pictures uploaded.  Check them out in the Photo Albums / Trips / [OZ](http://www.johnandjeri.com/Albums/folderview.aspx?path=Trips%2fOZ%2f&) section.', ''+CHAR(13)+CHAR(10)+'After a bit of an arm wrestling session with internet cafe, we managed to get some pictures uploaded.  Check them out in the Photo Albums / Trips / [OZ](http://After a bit of an arm wrestling session with internet cafe, we managed to get some pictures uploaded.  Check them out in the Photo Albums / Trips / &lt;a href=&quot;http://www.johnandjeri.com/Albums/folderview.aspx?path=Trips%2fOZ%2f&&quot;&gt;OZ&lt;/a&gt; section.) section of our site. '+CHAR(13)+CHAR(10)+'', '2007-03-31 00:00:00', NULL, 1, 1, 2427, '2007-04-01 21:16:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-04-01 21:16:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(17, 'Day 10(?):  We get to ride a helicopter!!', 'Helicopters, glaciers and driving on the wrong side of the road (oh my!!)', ''+CHAR(13)+CHAR(10)+'Today will  be our first attempt at driving.  Should be a piece of cake - but those round-abouts are really scary!  I think I''ll give John the first shift and work as navigator and snack provider.  On our way to Fox Glacier today - taking a helicopter up, then we''ll hike around, stay the night in Chancellor Hut, stomp around some more the next day and the ''copter will come for us again later that day (the only way to travel : ).  Pics to follow in a couple of days!'+CHAR(13)+CHAR(10)+'', '2007-04-01 00:00:00', NULL, 1, 1, 2212, '2007-04-02 18:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-04-02 18:00:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(18, 'Velociraptor''s are not just in Jurassic Park', 'The day started out like any other adventure, a little disappointing.  We stayed in a human sized bug zapper, got turned away at 7:40 and told to report at 8:50 for our taxi up the glacier due to the heavy cloud cover.  So we went and had an overpriced, uncooked breakfast of fruit and Wheat Bix.  Then, things started to pick up.', ''+CHAR(13)+CHAR(10)+'We loaded our gear and climbed aboard the heli with our guides Tracey and Dennis.  We had a very nice flight up to a solid landing pad above the hut.  The views were incredible!!   We took roughly 1000 pics.  There are a few shots that show the rainforest on the edge of the glacier (weird).  Dennis cooked a butter chicken & split a bottle of NZ''s wine.  The morning came quick with the Kea''s (raptor) trying to peal back the roof of our tin hut.  Once the terror lifted, we were able to bushwack our way onto the surface of the glacier for a little ice climbing and slips & slides through the ice caves.'+CHAR(13)+CHAR(10)+'', '2007-04-07 00:00:00', NULL, 1, 1, 3874, '2007-04-07 04:17:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-04-07 04:20:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(19, 'Zorbing in Rotorua', 'We made the trek into Rotorua for our first Zorb, where it all began. (zorb)', ''+CHAR(13)+CHAR(10)+'It is a great big hampster wheel, for humans!  the stuffed us in one, poured a couple gallons of hot water in, then pushed us down the hill.  That was the funniest thing you have ever seen (or been in).  Went in dry and leary, and came out wet and laughing our asses off!  It was great!!!  A true kiwi adventure!'+CHAR(13)+CHAR(10)+'', '2007-03-07 00:00:00', NULL, 1, 1, 2130, '2007-04-07 04:24:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-04-07 04:24:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(20, 'Spelunking - Hazeltine Style', 'Tight spaces, abseiling (rappelling),cold water, absolute darkness and a couple glow worms describes Waitomo Caves.  We went on a "dodgy" caving trip yesteday, got soaked to the bone and a little battered and bruised - it was "classic"!!', ''+CHAR(13)+CHAR(10)+'If you''ve got scrapes, bruises & wake up knackered you know you''re having fun!  We spent most of the day underground, exploring the caves - the trick is that they teach you the ropes (literally) - then leave you to find your own way out!  It was tons of fun - tramping through water up to our chests, abseiling through waterfalls & traversing kilometres of rope line along the cave ledges.  Happy to report that we''ve successfully tackled the drving here - except for the turn signals!  (Daddy -  u r right, they''re on the wrong side of the steering column!)'+CHAR(13)+CHAR(10)+'', '2007-04-09 00:00:00', NULL, 1, 1, 2345, '2007-04-11 00:32:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-04-11 00:32:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(21, 'We got tattoos!!!!', 'Yes, you can see John''s - no, mine will most likely not see the light of day :)  Yes, it hurt a little (John teared up) (not) - but compared to whacking into rocks and falling down waterfalls - it was a piece of pie.', ''+CHAR(13)+CHAR(10)+'We figured we should mark our time in NZ with something permanent - not really big on souvenirs (backpack & all) - so what''s more permanent than ink jabbed into the skin?  Besides, it was really raining hard & know you wouldn''t want us getting hurt driving (because the turn signals & wipers are on the wrong side).  Gotta run - there''s a tongue piercing place down the block...  Miss you!!!'+CHAR(13)+CHAR(10)+'', '2007-04-10 00:00:00', NULL, 1, 1, 2559, '2007-04-11 22:48:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-04-11 22:48:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(22, 'Back on OZ', 'After a couple days chillin in Auckland, we filed our police report and caught our very, very late flight to Cairns, Australia on Friday the 13th.', ''+CHAR(13)+CHAR(10)+'Yes, you read that right.  We filed a police report.  Jeri went on a crime spree....  not really, but she did notice that someone  nicked our license plate from our rental car.   Jeri had to call the Auckland police to file the report in case the cops noticed it on our way to the airport.  Anyhow, we made it about 5 hours early thanks to an untimely lightening strike to our airplane...they switched it out and gave us a new one fully stocked with pies & ice cream!!! '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+'', '2007-04-13 00:00:00', NULL, 1, 1, 2421, '2007-04-14 23:45:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-04-14 23:45:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(23, 'Koalas, wallabies & roos - oh my!', 'And the dream became reality!  Jeri got to squeeze (gently) Banjo (the 2 year old koala) at Billabong Sanctuary.  I got to hold Nugget, the 40 kilo Wambat.', ''+CHAR(13)+CHAR(10)+'This place was great!  We bought a couple bags of seed figuring it would be good to toss at the ducks.  As it turns out, they let the roos roam around and beg for seed.  It was pretty kool, especially the really big red one!!!  They have a tendency to get a little friendly:)  Jeri (and I) got her chance to hold Banjo, one of several furry little buggers they had hanging from the trees.  We also got to watch the Croc feeding.  We were happy to watch from a distince, behind a big fence. '+CHAR(13)+CHAR(10)+'', '2007-04-17 00:00:00', NULL, 1, 1, 2439, '2007-04-20 00:02:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-04-20 00:02:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(24, 'Whitsundays by paddle', 'We hit Airlie Beach on April 14th (we think) to get ready.  Again, we were expecting the worst...the rain was pretty bad and the wind was cranking.  Not the best recipe for a sea kayaking trip across the Coral Sea.', ''+CHAR(13)+CHAR(10)+'We had to delay our trip by one day...it was not too hard to spend a day flopped by the lagoon doing absolutely nothing.  We managed!  We took off the next morning, equipped with a double kayak, our campig gear, and a small bottle of the best rum in Oz.  It took us about 6 hours to find a secluded island 16 kilometers away with our own **private** beach with some fairly spectatular views of the Great Barrier Reef.  It may have been better than Jamaica! '+CHAR(13)+CHAR(10)+'', '2007-04-17 00:00:00', NULL, 1, 1, 2511, '2007-04-20 00:14:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2007-04-20 00:14:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(25, 'Australia Zoo...funky turtles among other things!', 'We hit Australia Zoo on April 24th on our way to Brisbane.  The Croc hunter started a pretty neat little zoo.. Crikey!', 'Somewhere between Hervey Bay and Brisbane is a pretty cool little zoo... aptly named "Australia Zoo".  They had a full schedule of animal feedings, from elephants to turtles.  They even offered the koala holding and some "alone time" with the wombats.  To make it even better, they had the kangaroo areas where you can get up close with the little buggers.  I think they turn the big roos into steaks.  We even had the opportunity to catch a couple giant sea turtles in a moment of passion.  We have it on film and are considering selling it to the girls gone wild folks;)', '2007-04-26 00:00:00', NULL, 1, 1, 2511, '2007-04-26 23:34:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-04-26 23:34:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(26, 'Wine tour in the Hunter Valley on our last full day', 'Beware of American tour guides that swear they are "certified" boomerang instructors...especially when they are from Jackson Hole, Wyoming.', 'As you may have guessed, our tour guide was a bit of a dork, but that didn''t ruin the wine.  We had a great tour and sampled several local boutique wineries, and got our "official" boomerang instruction.  Some of you may get to try some sampling as well, assuming the customs folks take it easy on us and the baggage folks don''t play any rugby with our bags.', '2007-04-26 00:00:00', NULL, 1, 1, 6074, '2007-04-26 23:40:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-04-26 23:40:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(27, 'Our Vacation down under is officially over', 'As the alarm clock rang this the Monday morning, it was official, we are not on vacation any more.', ''+CHAR(13)+CHAR(10)+'Not too bad, 5 weeks, 10 flights, 16 airports, 3 rental cars, a 4x4 bus, a few trains, and a handful of shuttles, we are back to work.  It was a pretty good run through the southern hemisphere.  Now we have to learn how to drive on the &quot;right&quot; side of the road again. '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Keep watching, we will be loading a ton of pictures this week.  Our site should be working a whole lot better now that our &quot;web developer&quot; tweeked a few of the run-away bugs we were seeing.'+CHAR(13)+CHAR(10)+'', '2007-04-30 00:00:00', NULL, 1, 1, 13997, '2007-05-01 00:22:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-05-01 00:23:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(28, 'Backyard Saga', 'Now that we have been in our new house for 9 months, we finally got around to a little yard art.', ''+CHAR(13)+CHAR(10)+'![](http://www.johnandjeri.com/Albums/image.ashx?path=New+House%2fBackyard+LandScape%2fP1020386.jpg%2f)'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'# They threw in the socks! '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'As of now, we have about three quarters of our backyard finished.  We worked with [www.perspectivelandscapinginc.com](http://www.perspectivelandscapinginc.com) to give us something to put is a couple steps in front of the Joneses. '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'They wrapped up a solid week of cutting stones for patios & a walkway as well as brining in river rock, multch, and planting a bundle of trees.  The net result is a pretty neat and fairly low maintenance setup. '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We have some pics of the before, during, and if I can keep up with the photos, a few after pics.  Check them out in our photo album at [www.johnandjeri.com/Albums/image.ashx](http://www.johnandjeri.com/Albums/image.ashx?path=New+House%2fBackyard+LandScape%2fP1020386.jpg%2f)  .'+CHAR(13)+CHAR(10)+'', '2007-06-08 00:00:00', NULL, 1, 1, 2641, '2007-06-09 16:21:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-06-09 16:32:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(29, 'Jeri''s Recipe Collection', 'We had talked about adding a recipe database to the site for a while now (before the wedding).  Anyhow, after much procrastination, We finally got it put together. Check it out!!!', ''+CHAR(13)+CHAR(10)+'The new recipe section is just that...new.  We did some preliminary testing, but as of Halloween (''07), it is online.  The basic idea is to give us a location where we can store recipes.  There are a bundle of new features that will come along over the next few months.  We will allow people to add comments and ratings to each recipe and print a nice copy so you don''t have to worry about spilling olive oil on your computer.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We will also work on a search feature to allow filtering recipes based on ingredients, categories, calories...and anything else that might be handy.  If you have a feature that we should add, please let us know.  The easiest way is to post the new feature to this posting.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'enjoy!!!'+CHAR(13)+CHAR(10)+'', '2007-10-31 00:00:00', NULL, 1, 1, 4703, '2007-11-01 16:03:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2007-11-01 16:03:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(30, 'Beach Guy and Girl - Hermosa Beach, CA', 'A beach house with a view of volleyball players that are "ESPN good", a lively party crowd - what could possibly go wrong?', ''+CHAR(13)+CHAR(10)+'Rain, wind and a touch cold weather.  We''ve both been working really hard this year - John''s really been burning the candle at both end (working until 2 -6 AM the next day - then going to the office) - so we decided to reward ourselves with a little r&r this past weekend.  We found this great little place in Hermosa Beach, CA and stayed Friday - Sunday.  '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'I was in California all week (San Fran, then L.A.), so John flew out and joined me in LA.  It was gorgeous weather all week - but wouldn''t you know it - we had clouds and damp on Saturday.  It was fine though - gave the beach &quot;atmosphere&quot;, we walked for miles and miles on the beach (poked at all of the dead jellyfish and saved starfish that washed up) and we added to our sweatshirt collection (we packed shorts).  The room was really great - it had a massive tub and a fireplace - I light a mean Duraflame fire : )  '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We had a flight out on Sunday - and the sun was out, not a cloud in the sky - darn it!!  It may not have been ideal but was so nice to decompress for a little while and enjoy each others company.'+CHAR(13)+CHAR(10)+'', '2008-03-05 00:00:00', NULL, 1, 1, 15341, '2008-03-05 15:14:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2010-01-03 18:25:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(31, 'Learning to float', 'Standing next to Horsetooth Reservoir last year in the midst of a particularly hot summer day, we couldn’t help but notice the boats zooming by with groups of happy passengers, including those tied to the back getting drug through the water.', ''+CHAR(13)+CHAR(10)+'![25 inches in case you are measuring.](http://www.johnandjeri.com/Albums/image.ashx?imagewidth=500&path=Hunting+and+Fishing%2fFishing+Trips+2007%2fDelany%2fP1020475.jpg%2f)In case you are wondering about one of the drivers...this fish barely fit into the canoe.  It was all we (me and Naya) could do to keep the canoe from topsizing.  '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'The fine folks at Crowley managed to find a boat that fits into our garage and still has enough power to drag us screaming through the water. Hopefully we will figure out how to catch fish from this thing.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' ![First day at the house](http://www.johnandjeri.com/Albums/image.ashx?imagewidth=500&path=Life%2fBoat%2fP1020582.jpg%2f) '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Hopefully we will be able to get out a ton this summer.  Feel free to post any pointers on how we can catch fish from this thing now.  '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+' '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Our new boat is a Sylvan Pro Sport 1600.  It should have enough power to pull a body thgouth the water at a very high rate of speed.'+CHAR(13)+CHAR(10)+'', '2008-04-24 00:00:00', NULL, 1, 1, 7593, '2008-04-23 17:53:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2008-04-23 17:53:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(32, 'Storm Chasers', 'Just a typical Sunday afternoon.  Took the dog to the park, watched a little Olympic Water Polo, and saw my first tornado touch down.', ''+CHAR(13)+CHAR(10)+'As I was heading to Walmart to pickup some fixins for the grill I noticed a small little funnel poking out of the clouds.  I called Jeri to let her know...besides, who does not want to see a tornado.  She got some really good pics from the upstairs window. ![Castle Rock Funnel Cloud](http://www.johnandjeri.com/Albums/image.ashx?imagewidth=80&path=Life%2fStorm%2fP1020713.jpg%2f)'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'The small picture here is a shot Jeri got from upstairs.&nbs', '2008-08-24 00:00:00', NULL, 1, 1, 64586, '2008-08-24 21:00:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2008-08-24 21:32:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(33, 'Test Article', 'this is a sample.', ''+CHAR(13)+CHAR(10)+'This is the article. at 6:07 and at 6:32'+CHAR(13)+CHAR(10)+'', '2009-11-30 00:00:00', NULL, 1, 1, 6789, '2009-12-02 20:02:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2009-12-15 21:45:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(34, 'Planes, Planes, and more blasted planes', 'We managed to get out of dodge before the snow started flying...', 'Surprisingly, we managed to make all of our flights and nothing was delayed.  I blame Jeri for that.  My original thought was to head out on the 23rd..which in retrospect, would not have worked out very well.  Since she was all over that, we managed to get here.  The biggest issues we had were a bundle of very unhappy toddlers.  I am pretty sure half the plane from Dallas to Miami was packed with screamers.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We landed in Quito, Ecuador last night with enough time to rush to our hotel (Relicario De Carmen) and set the alarm clock.  The hotel was real nice, very old townish.  It was built in the 1700´s ...sometime after the Incas and the Spanish.  We were told there are normally great views at night, but due to the drought and ensuing rolling blackouts (yeah, it happens in more places than LA), the view was somewhat dark and unimpressive.  Maybe we can check it out on our return trip.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'This morning we had an alarm scare, thought we missed our ride to the airport. As it turns out, if you slap the alarm clock, it advances an hour as pay back. I´ll be more careful going forward. On a side note, we can fully dress and pack in less than two minutes.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We spotted our first Galapagos Turtle this morning around 12:00.  It was crossing the road (insert clever joke here).  Eventually we managed to get to a private farm where the turtles roamed freely.   Look for picture we took of us trying on our turtle suits.  It seemed wrong on a few levels, but Jeri insisted  ;).'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'From the turtle farm we walked through a lava tube. It was pretty neat..except for the belly crawl through the bat guano.  Note to self, we need to find a place to wash our clothes.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'That´s all we have for today.  Look for our next post in a few days. If we get ambitious, we´ll try to get a couple photos uploaded. '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'<span style="color: #ff0000">Enjoy the snow and Merry Christmas!</span>', '2009-12-23 00:00:00', NULL, 1, 1, 7055, '2009-12-24 17:19:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2009-12-24 17:19:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(35, 'Mudslides, snorkeling and pinguinos', 'From Santa Cruz to Isabela', 'In Santa Cruz we wrapped up with a fine dinner at place named The Garrapatta (which apparently is named after a cow parasite - no one knows why they call it that) - but never mind the name - it was an excellent dinner and I had a real Pi�a Colada (incredible!!!!).  So far, no signs of mooing from either me or John so I think we�re in the clear.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'The next morning (12/26) we went to the Darwin Center and learned all about how they are breeding turtles and iguanas.  Luckily, we didn�t see any turtle free-love while we were there - they try to keep it strictly &quot;G-rating&quot; (its a family show).� Later in the day we took a 2 1/2 hour boat trip to Isabela and I didn�t throw up - yea me!'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We spent the next couple of days touring the volcanos, riding horses (ouch...trotting hurts) and snorkeling.  We saw land turtles, sea turtles, swam with sea lions and penguins - it was unbelievable!  I haven�t even mentioned the food we�ve eaten - we�ll cover that in the next post.  (Sorry for the weird spellings and missplaced grammatical symbols - the keyboards here are not like ours (no - I am not making that up).'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Adios for now - we have dinner scheduled for 7.  (Grandpa - happy birthday!  We were thinking of you on **your** birthday - but the internet was not working and we could not post anything that day!)', '2009-12-26 00:00:00', '2015-12-31 00:00:00', 1, 1, 1635, '2009-12-28 20:07:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2009-12-28 20:07:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(36, 'Back in old Santa Cruz', 'After the "Very Fast" boat ride, we made it back to our old stomping grounds for our last night in the islands.', 'We wrapped up our trip to Isabela with dinner at Casa de Marita.  This was something you would expect to see on one of the Anthony Bourdain specials.  Our guide, Marlo(maybe a silent &quot;n&quot; here?) took us to up three flights of stairs that gave the impression we were heading to someone´s kitchen.  As it turns out, everybody goes there...  Lots of the resturants here don´t have any signs, so unless someone leads you to the table, you could starve.  '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Our last night in the hotel was somewhat interesting. They were trying to bring a fully pre-fabbed pool over the top of a three story building to drop it in a hole in the center of the courtyard.  Needless to say, it was still hanging from the side if the building when we left it. Then the water was out in the hotel. I guess that is one of the downsides of living in the Galapagos.  Water and power tend to go away without warning..or promise of a morning shower.  Since our fast boat left at 5:30 AM ..Yeah 5:30 AM.  I guess someone forgot to tell them we were on vacation.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Today was a nice hike (loosely translated: death march), a bit warm (felt like 120º), and the water was cool and exhilerating (we saw shark like fish in the waves).  After baking in the sun, we decided to do like the locals and take a long deserved siesta.  Someone should petition to incorporate the siesta in the States.  After waking all refreshed and ready to do something, Jeri took some really cool pictures of the sea lions down by the fish market.  One was bellied up to the bar, his chin was on the cutting board.  I am glad Naya never learned to beg like that.  It was acting like a garbage disposal for the left over fish parts. That looked handy. Note to self, take a sea lion fishing with us next time.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We have one more dinner out tonight and then we head back to the main land to do a little exploring in Quito. We have read about how they do it..and it should be interesting. They make these effigies (flammable dummies) of things they don´t like. At midnight, they light them on fire..and mix in a few fireworks.  That reminds me, we should bring lots of water.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'', '2009-12-29 00:00:00', NULL, 1, 1, 6584, '2009-12-29 18:48:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2009-12-29 18:48:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(37, 'Delayed flights, ham sanduches and roller coaster cabs', 'Our last couple of days didn´t go completely as planned, but there´s something to be said for spontaneity.', 'Well, our flight out of the Galapagos was delayed by two hours.  Not really too bad when you think about it - but there is very little to do at the Baltra airport.  It�s basically dusty, windy and open to the elements - not to mention that we only saw one iguana during our wait.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Once we took off, it took an hour and a half to get to Guayquil.  The flight attendants here are superb - they were able to serve us a full meal (hot meal - with actual forks, knives and spoons - okay they were plastic - but still - very cool) and drinks all in that time.  Then there was massive confusion as we had to get off the plane (in Guayquil - not in mid-air - whew) and get on a smaller plane.  All was not lost though - John had the opportunity to get a cup of coffee (Americano - of course) before we boarded.  I, on the other hand, had a chance to experience the joys of the modern plumbing - motion sensors and all - it was incredible!'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We arrived late to Quito, so we ate dinner at the restaurant and it was out of this world!  The food and service are top notch - and the hotel is 5 star (not kidding).  I feel like a huge water buffalo stomping around here - everyone else is so refined - but it�s been great.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We got up early and took a taxi to the Mitad de Mundo (translation: Middle of the World) and took pictures at the monument they have created to mark the equator.  John�s phone has a GPS app that will tell you longitude and latitude, so he whipped it out to check and found that it was actually 168� off, so we had to exit the monument and walk through Quito until the latitude read 0.0.0� before we could head back to the hotel.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We�re off to walk around the city now.  We�ve already seen all of the stuffed dolls that they�re selling to burn tonight at midnight.  Can�t wait to see the festivities!  We�ll be home tomorrow so this will be our last post from Ecuador.  Feliz A�o everyone!'+CHAR(13)+CHAR(10)+'', '2009-12-31 00:00:00', NULL, 1, 1, 64396, '2009-12-31 10:49:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2009-12-31 10:49:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(38, 'Latin American Vacation Wrapped Up', 'Not bad, 11 days, several flights, a new passport stamp, and several hundred new photos.', 'As much as I hate to see vacation come to an end, there is something comforting about coming back home.  Might be sleeping in your own bed or being greeted by a happy tail wagging dog, either way, it was fun.  '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We just wrapped up our two day project of adding titles and comments to our photos. It may not seem like a lot of work, but there are over 300 photos.  You can browse through all the photos in our [<span style="color: #0000ff">Galapagos Islands</span>](http://www.johnandjeri.com/Albums/folderview.aspx?path=Trips%2fGalapagos+Islands%2f&) trip album.  '+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Our trip started on December 22nd and after three days of travel through Dallas, Miami, and Quito Ecuador, we managed to find our way to Santa Cruz Island.  We spent 8 days and 7 nights exploring several islands, including Santa Cruz, Baltra, North Seymour, and Isabela Island.  During our stay in the islands, we caught several creatures on film, walked (and belly crawled) through lava tunnels, rode horses to the top of a volcano, snorkled with sea lions and penguins, and had a jolly good holiday trip.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'We celebrated Christmas on North Seymour and Santa Cruz and New Years in Quito Ecuador.  Our trip home hit a couple delays along the way, but we made it home in one piece.  All in all, this was one of the best vacations we have ever been on.', '2010-01-03 00:00:00', NULL, 1, 1, 17256, '2010-01-03 18:57:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2010-01-03 20:35:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', NULL, NULL, NULL)
    ,(40, 'Our little Ace', 'Our little Ace', '<p class="MsoNormal" style="margin: 0in 0in 0pt"><font color="#000000" size="3" face="Times New Roman">John and I didn’t post any news that we were expecting a little one at the end of September but were very excited and having fun putting together baby furniture,<span style="mso-spacerun: yes"> </span>painting the nursery and attending childbirth classes. <span style="mso-spacerun: yes"> </span>Unfortunately, the baby died and he was delivered on July 18<sup>th</sup>. <span style="mso-spacerun: yes"> </span>He was a beautiful baby boy with dark hair and a cute little nose - we named him Ace.</font>'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'<p class="MsoNormal" style="margin: 0in 0in 0pt">'+CHAR(13)+CHAR(10)+'<o:p><font color="#000000" size="3" face="Times New Roman"> </font></o:p>'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'<p class="MsoNormal" style="margin: 0in 0in 0pt"><font color="#000000" size="3" face="Times New Roman">It’s important for me to post this so that others know that he existed – and even though you did not know him – he was a big part of our lives for 7 ½ months. <span style="mso-spacerun: yes"> </span>Even within a short span of 30 weeks he held our hearts, hopes and dreams. <span style="mso-spacerun: yes"> </span>He was our first child and will dwell within us always.</font>'+CHAR(13)+CHAR(10)+'', '2010-08-17 00:00:00', NULL, 0, 1, 6320, '2010-08-17 18:29:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', '2010-08-17 18:29:00', 'C00BEAFF-AF9B-4B78-9D42-4B67BE242E66', NULL, NULL, NULL)
    ,(41, 'Site Refresh from Asp.net webforms (2006) to .NETCore & React', '## We''re Back — and We Brought Better Tech'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'After twenty years and a few too many dusty WebForms pages, johnandjeri.com has been completely rebuilt from the ground up.', ''+CHAR(13)+CHAR(10)+'![.Net](https://img.shields.io/badge/.NET-5C2D91?style=for-the-badge&logo=.net&logoColor=white)'+CHAR(13)+CHAR(10)+'![React](https://img.shields.io/badge/react-%2320232a.svg?style=for-the-badge&logo=react&logoColor=%2361DAFB)'+CHAR(13)+CHAR(10)+'![GitHub](https://img.shields.io/badge/github-%23121011.svg?style=for-the-badge&logo=github&logoColor=white)'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'![Site panorama](/images/panorama.jpg)'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'## We''re Back — and We Brought Better Tech'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'After twenty years and a few too many dusty WebForms pages, johnandjeri.com has been completely rebuilt from the ground up.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'The new stack is fast, modern, and actually enjoyable to work on:'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'- **React + TypeScript** on the frontend, powered by Vite and Mantine UI'+CHAR(13)+CHAR(10)+'- **.NET 10** on the backend, orchestrated via .NET Aspire'+CHAR(13)+CHAR(10)+'- **SQL Server** for storage, with GitHub Actions handling deploys automatically'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'The recipes are still here. The travel stories are still here. The pig is still in the favicon.'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'Some things never change. ??'+CHAR(13)+CHAR(10)+''+CHAR(13)+CHAR(10)+'![1000000842.jpg](/api/attachment/11/content)', NULL, NULL, 1, 1, 24, '2026-07-02 00:05:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '2026-07-11 01:25:00', 'B189EB60-B5B5-458B-B54C-B18CC35619DD', '', NULL, NULL)
